sql:
SELECT COUNT(*) AS total_datasets
FROM datasets
WHERE dataset_id LIKE '2020%';

SELECT dataset_id, COUNT(*) AS TotalAnnotations
FROM dataset_annotations
GROUP BY dataset_id;

SELECT name
FROM datasets
WHERE dataset_id IN (
  SELECT dataset_id
  FROM dataset_annotations
);

SELECT format_name, description 
FROM formats 
WHERE format_id = 1;

SELECT dataset_id, COUNT(*)
FROM dataset_annotations_history
GROUP BY dataset_id;

SELECT datasets.dataset_id, datasets.name AS dataset_name, formats.format_name
FROM datasets
INNER JOIN formats ON datasets.format_id = formats.format_id;

